458	#[cfg(test)]
459	mod tests {
460	    use super::*;
461	
462	    #[test]
463	    fn escape_record_metachars() {
464	        assert_eq!(escape_record("<$A, $A, 'g'^~ex>"), "\\<$A, $A, 'g'^~ex\\>");
465	        assert_eq!(escape_record("a|b{c}"), "a\\|b\\{c\\}");
466	        assert_eq!(escape_record("no meta 'g'^~x"), "no meta 'g'^~x");
467	    }
468	
469	    #[test]
470	    fn fact_flat_spacing_matches_corpus() {
471	        // Fr( ~ex )  — a fact pads inside its parens.
472	        assert_eq!(Fact::new("Fr", vec![Term::fresh("ex")]).render_flat(), "Fr( ~ex )");
473	        // zero-arg fact: NoA( )
474	        assert_eq!(Fact::new("NoA", vec![]).render_flat(), "NoA( )");
475	        // Out( pk(~ltkA) ) — outer fact pads; inner function pk(...) does NOT.
476	        let f = Fact::new("Out", vec![Term::app("pk", vec![Term::fresh("ltkA")])]);
477	        assert_eq!(f.render_flat(), "Out( pk(~ltkA) )");
478	        // !SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )
479	        let f = Fact::new(
480	            "!SessionKey",
481	            vec![
482	                Term::tuple(vec![Term::pubv("A"), Term::pubv("A"), Term::exp(Term::cst("g"), Term::fresh("ex"))]),
483	                Term::pubv("A"),
484	                Term::fresh("ex"),
485	            ],
486	        );
487	        assert_eq!(f.render_flat(), "!SessionKey( <$A, $A, 'g'^~ex>, $A, ~ex )");
488	    }
489	
490	    #[test]
491	    fn info_cell_shape() {
492	        assert_eq!(render_info("vf.5", "Fresh", &[]), "#vf.5 : Fresh");
493	        let acts = vec![Fact::new("RegKey", vec![Term::pubv("R.4")])];
494	        assert_eq!(render_info("vr.9", "generate_ltk", &acts), "#vr.9 : generate_ltk[RegKey( $R.4 )]");
495	    }
496	
497	    #[test]
498	    fn wrap_format_reproduces_observed_action_cell() {
499	        // Reproduce the observed record cell verbatim (from corpus fixture
500	        // 004825b0f93b1a8c.dot, node n24's info cell): the action list of
501	        // Corrupt_SessionKey wraps, aligning the continuation under the `[`.
502	        //   #vr.2 : Corrupt_SessionKey[Corrupt( $A ),\l<27 nbsp>BeforeExpire( <…> )]\l
503	        // The info prefix `#vr.2 : Corrupt_SessionKey[` is exactly 27 columns, so
504	        // the continuation indent is 27 `&nbsp;`.
