251	/// An anonymous block carrying a `rank` and inner statements — used for the
252	/// legend's `{ rank="sink"; … }`.
253	#[derive(Clone, Debug)]
254	pub struct RankBlock {
255	    pub rank: String,
256	    pub body: Vec<Stmt>,
257	}
