def escape(s):
    o=[]
    for c in s:
        if c in '<>{}|': o.append('\\'+c)
        else: o.append(c)
    return ''.join(o)

def split_top(s, sep=', '):
    # split by top-level ", " respecting () <> [] and quotes
    parts=[]; depth=0; i=0; cur=''
    while i < len(s):
        c=s[i]
        if c in '(<[': depth+=1; cur+=c; i+=1
        elif c in ')>]': depth-=1; cur+=c; i+=1
        elif depth==0 and s[i:i+2]==sep:
            parts.append(cur); cur=''; i+=2
        else: cur+=c; i+=1
    parts.append(cur)
    return parts

def is_tuple(s): return s.startswith('<') and s.endswith('>')

def run_layout(open_text, start_col, units):
    # units: list of dict(sep, text, indent, hard)
    lines=[]; cur=open_text; col=start_col; line_indent=0
    for u in units:
        cur+=u['sep']; col+=len(u['sep'])
        if u['hard'] or col+len(u['text'])>W:
            lines.append((line_indent, cur)); line_indent=u['indent']; cur=u['text']; col=u['indent']+len(u['text'])
        else:
            cur+=u['text']; col+=len(u['text'])
    lines.append((line_indent, cur))
    return lines

def layout_tuple(elems, base_col):
    # < at base_col ; elements at base_col+1
    open_col=base_col+1
    units=[]
    for i,e in enumerate(elems):
        units.append(dict(sep=('' if i==0 else ', '), text=e, indent=open_col, hard=False))
    units.append(dict(sep='', text='>', indent=base_col, hard=False))
    return run_layout('<', base_col+1, units)   # start_col after '<'

def layout_fact(flat):
    # flat = NAME( args )
    if len(flat)<=W: return [(0, flat)]
    lp=flat.find('( ')
    name=flat[:lp]
    open_str=flat[:lp+2]   # "NAME( "
    assert flat.endswith(' )'), flat
    content=flat[lp+2:len(flat)-2]
    open_col=len(open_str)
    args=split_top(content)
    if len(args)==1 and is_tuple(args[0]):
        inner=args[0][1:-1]
        telems=split_top(inner)
        tlines=layout_tuple(telems, open_col-1)  # '<' sits at open_col-1? NO
        # Actually '<' sits right after "NAME( " at col=len(open_str)=open_col. tuple base_col=open_col.
        # fix:
        tlines=layout_tuple(telems, open_col)
        lines=[(0, open_str+tlines[0][1])]
        for t in tlines[1:]: lines.append(t)
        lines.append((0, ')'))
        return lines
    # multi-arg fill, hard-close )
    units=[]
    for i,a in enumerate(args):
        units.append(dict(sep=('' if i==0 else ', '), text=a, indent=open_col, hard=False))
    units.append(dict(sep='', text=')', indent=0, hard=True))
    return run_layout(open_str, open_col, units)

def wrap_cell(flat):
    lines=layout_fact(flat)
    if len(lines)==1 and lines[0][0]==0:
        return escape(lines[0][1])
    out=''
    for ind,txt in lines:
        out+='&nbsp;'*ind + escape(txt) + '\\l'
    return out

