#!/usr/bin/env python3
# Scrape the injective line for the single theory served on PORT.
import sys, re, html, json, urllib.request
PORT = sys.argv[1]
BASE = f"http://127.0.0.1:{PORT}"

def get(path, timeout=180):
    with urllib.request.urlopen(BASE + path, timeout=timeout) as r:
        return r.read().decode("utf-8", "replace")

def textify(s):
    return html.unescape(re.sub(r"\s+", " ", re.sub("<[^>]+>", " ", s))).strip()

idx = get("/")
# support both trace and equiv (diff) theories
ms = re.findall(r'/thy/(trace|equiv)/(\d+)/overview/help', idx)
if not ms:
    print("NO_THEORY_LINK"); sys.exit(0)
out = []
for kind, i in ms:
    try:
        raw = get(f"/thy/{kind}/{i}/main/rules")
    except Exception as e:
        out.append(f"[{kind}{i}:ERR {e}]"); continue
    body = raw
    try:
        j = json.loads(raw)
        if isinstance(j, dict) and "html" in j:
            body = j["html"]
    except Exception:
        pass
    low = body.lower()
    k = low.find("injective instances")
    if k < 0:
        out.append(f"[{kind}{i}:no-header]"); continue
    tail = textify(body[k + len("injective instances"):])
    cut = tail.lower().find("multiset rewriting rules")
    if cut >= 0:
        tail = tail[:cut].strip()
    out.append(tail)
print(" || ".join(out))

