#!/usr/bin/env python3
import re, glob, sys
CORP="/home/kamilner/tamarin-cleanroom/graphdot/oracle/dot_corpus"

def split_top(s, opench='{', closech='}', sep='|'):
    # split s on top-level `sep`, honoring {} nesting and backslash-escapes; also skip () <> [] ? 
    # For record label group split we only need brace + pipe with escape awareness.
    parts=[]; depth=0; cur=[]; i=0
    while i < len(s):
        c=s[i]
        if c=='\\' and i+1<len(s):
            cur.append(s[i:i+2]); i+=2; continue
        if c=='{': depth+=1; cur.append(c)
        elif c=='}': depth-=1; cur.append(c)
        elif c==sep and depth==0:
            parts.append(''.join(cur)); cur=[]
        else: cur.append(c)
        i+=1
    parts.append(''.join(cur))
    return parts

def flat_width(cell):
    # cell text after "<nK> " (may contain \l, &nbsp;, escapes). Reconstruct flat visual width.
    lost = len(re.findall(r',\\l', cell)) + len(re.findall(r'\\l\)', cell))
    t = cell.replace('\\l','')
    t = t.replace('&nbsp;','')
    # unescape record metachars to 1 visual col each
    for a,b in [('\\<','<'),('\\>','>'),('\\{','{'),('\\}','}'),('\\|','|')]:
        t=t.replace(a,b)
    return len(t) + lost

def count_actions(infocell):
    # infocell flat-ish; count top-level actions in [...]
    b=infocell.replace('\\l','')
    b=b.replace('&nbsp;','')
    for a,x in [('\\<','<'),('\\>','>'),('\\|','|'),('\\{','{'),('\\}','}')]: b=b.replace(a,x)
    i=b.find('[')
    if i<0: return 0
    if i+1<len(b) and b[i+1]==']': return 0
    depth=0; acts=1; j=i+1
    while j<len(b):
        c=b[j]
        if c in '(<[': depth+=1
        elif c==']' and depth==0: break
        elif c in ')>': depth-=1
        elif c==',' and depth==0: acts+=1
        j+=1
    return acts

def parse_record(label):
    # label = {grp|grp|grp} ; strip outer braces
