        assert_eq!(cell_budget(&[21, 98], 0), MIN_CELL_BUDGET);
        // Three cells: Σ is over ALL others (probe [p,28,28] flips at 87-56 = 31).
        assert_eq!(cell_budget(&[33, 28, 28], 0), 31);
